// carsfx.js — owner-supplied car SFX, appended to / overriding the SFX pack from
// soundfx.js so game.js decodes them like any other one-shot. Loaded AFTER
// soundfx.js and BEFORE game.js. Data-URL WAVs; file:// safe, no external refs.
//   brake       = low-speed stop chirp   (updateDriving)
//   tirescreech = hard/high-speed brake + traction loss (updateDriving)
//   horn        = replaces the stock car horn for ALL cars (playHornBuf)
if (typeof SFX_PACK !== "undefined") {
  SFX_PACK.brake = ["data:audio/wav;base64,"];
  SFX_PACK.tirescreech = ["data:audio/wav;base64,"];
  SFX_PACK.horn = ["data:audio/wav;base64,"];
  SFX_PACK.cut = ["data:audio/wav;base64,"];
}
